import { useState, useEffect, useCallback, useRef } from "react";
import { useTranslation } from "react-i18next";

import i18n from "./i18n";
import "./App.css";

// Constants
import { STAFF_NOTES, DURATION_KEYS, TIME_SIGNATURES, KEY_TO_NOTE } from "./constants/music";
import { STAFF_TOP, LINE_GAP, STAFF_LEFT, NOTE_START_X, BEAT_WIDTH, MEASURES_PER_LINE, SIXTEENTH_GAP_ADJUST } from "./constants/staff";
import { G_CLEF, REPEAT_PATHS } from "./constants/svgPaths";

// Utils
import { noteName, getNoteBeatValue, getDurationBeatValue, getTotalBeats, snapToGrid } from "./utils/music";
import { staffY, yToPos, getNoteX } from "./utils/staff";
import { playNote } from "./utils/audio";

// Hooks
import usePlayback from "./hooks/usePlayback";

// Components
import NoteHead from "./components/NoteHead";
import RestHead from "./components/RestHead";
import Beams, { calculateBeamGroups, getBeamDirection } from "./components/Beams";
import MenuBar from "./components/MenuBar";

// ─── Main App ─────────────────────────────────────────────────────────────────

export default function App() {
  const { t } = useTranslation();

  const [notes,       setNotes]       = useState([]);
  const [selectedIdx, setSelectedIdx] = useState(null);
  const [duration,    setDuration]    = useState("quarter");
  const [dotted,      setDotted]      = useState(false);
  const [triplet,     setTriplet]     = useState(false);
  const [slur,        setSlur]        = useState(false);
  const [accidental,  setAccidental]  = useState(null);
  const [noteSystem,  setNoteSystem]  = useState("solfeo");
  const [ghostNote,   setGhostNote]   = useState(null);
  const [timeSignature, setTimeSignature] = useState(TIME_SIGNATURES[0]);
  const [repeats, setRepeats] = useState({});
  const [hideLabels,  setHideLabels]  = useState(true);
  const [showShortcuts, setShowShortcuts] = useState(false);

  const containerRef = useRef(null);
  const svgRefs      = useRef([]);

  const {
    isPlaying, playheadBeat, tempo, setTempo,
    isMuted, setIsMuted,
    startPlayback, stopPlayback,
  } = usePlayback(notes);

  useEffect(() => { containerRef.current?.focus(); }, []);


  const focusContainer = useCallback(() => containerRef.current?.focus(), []);

  const saveScore = useCallback(() => {
    if (notes.length === 0) return;
    const data = { notes, repeats, timeSignature, noteSystem };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = "score.json";
    a.click();
    URL.revokeObjectURL(url);
  }, [notes, repeats, timeSignature, noteSystem]);

  const openScore = useCallback(() => {
    const input = document.createElement("input");
    input.type = "file";
    input.accept = ".json";
    input.onchange = (e) => {
      const file = e.target.files[0];
      if (!file) return;
      file.text().then(text => {
        try {
          const imported = JSON.parse(text);
          if (Array.isArray(imported)) {
            // Legacy format: just an array of notes
            setNotes(imported);
            setRepeats({});
            setSelectedIdx(null);
          } else if (imported && Array.isArray(imported.notes)) {
            setNotes(imported.notes);
            if (imported.repeats) setRepeats(imported.repeats);
            if (imported.timeSignature) setTimeSignature(imported.timeSignature);
            if (imported.noteSystem) setNoteSystem(imported.noteSystem);
            setSelectedIdx(null);
          } else {
            alert("Invalid format.");
          }
        } catch {
          alert("Could not parse file as JSON.");
        }
      });
    };
    input.click();
  }, []);

  // ── Add a note ──────────────────────────────────────────────────────────────
  const addNote = useCallback((noteData) => {
    playNote(noteData.note, noteData.octave, accidental);

    setNotes(ns => {
      const currentTotalBeats = getTotalBeats(ns);
      const snappedBeat = snapToGrid(currentTotalBeats, duration, triplet);

      const newNotes = [...ns];

      // If slur is active, mark the previous note as slur start
      if (slur && newNotes.length > 0) {
        const prevIdx = newNotes.length - 1;
        const prev = newNotes[prevIdx];
        if (!prev.isRest && !prev.slur) {
          newNotes[prevIdx] = { ...prev, slur: true };
        }
      }

      const newNote = {
        ...noteData,
        duration,
        dotted,
        triplet,
        accidental,
        id: Date.now() + Math.random(),
        startBeat: snappedBeat,
      };

      newNotes.push(newNote);

      if (triplet) {
        let tripletCount = 0;
        for (let i = newNotes.length - 1; i >= 0; i--) {
          const n = newNotes[i];
          if (n.triplet && n.duration === duration) {
            tripletCount++;
          } else {
            break;
          }
        }
        if (tripletCount >= 3) {
          setTimeout(() => setTriplet(false), 0);
        }
      }

      // Auto-deselect slur after the second note
      if (slur) {
        setTimeout(() => setSlur(false), 0);
      }

      return newNotes;
    });
    setAccidental(null);
    setDotted(false);
    setSelectedIdx(null);
  }, [duration, dotted, triplet, slur, accidental]);

  // ── Add a rest ────────────────────────────────────────────────────────────────
  const addRest = useCallback(() => {
    setNotes(ns => {
      const currentTotalBeats = getTotalBeats(ns);
      const snappedBeat = snapToGrid(currentTotalBeats, duration, triplet);

      const newRest = {
        isRest: true,
        duration,
        dotted,
        triplet,
        id: Date.now() + Math.random(),
        startBeat: snappedBeat,
      };

      const newNotes = [...ns, newRest];

      if (triplet) {
        let tripletCount = 0;
        for (let i = newNotes.length - 1; i >= 0; i--) {
          const n = newNotes[i];
          if (n.triplet && n.duration === duration) {
            tripletCount++;
          } else {
            break;
          }
        }
        if (tripletCount >= 3) {
          setTimeout(() => setTriplet(false), 0);
        }
      }

      return newNotes;
    });
    setDotted(false);
    setSelectedIdx(null);
  }, [duration, dotted, triplet]);

  // ── Recalculate startBeats after editing a note ────────────────────────────
  const recalcStartBeats = useCallback((notesList) => {
    let beat = 0;
    return notesList.map(n => {
      const snapped = snapToGrid(beat, n.duration, n.triplet);
      const updated = { ...n, startBeat: snapped };
      beat = snapped + getNoteBeatValue(updated);
      return updated;
    });
  }, []);

  // ── Update selected note property ──────────────────────────────────────────
  const updateSelectedNote = useCallback((prop, value) => {
    if (selectedIdx === null) return false;
    setNotes(ns => {
      if (selectedIdx >= ns.length) return ns;
      const note = ns[selectedIdx];
      if (note.isRest && (prop === "accidental" || prop === "pos")) return ns;
      const updated = [...ns];
      if (prop === "pos") {
        const noteData = STAFF_NOTES[value];
        if (!noteData) return ns;
        updated[selectedIdx] = { ...note, pos: value, note: noteData.note, octave: noteData.octave };
      } else {
        updated[selectedIdx] = { ...note, [prop]: value };
      }
      return recalcStartBeats(updated);
    });
    return true;
  }, [selectedIdx, recalcStartBeats]);

  // ── Keyboard handler ────────────────────────────────────────────────────────
  const handleKeyDown = useCallback((e) => {
    const key = e.key.toLowerCase();

    // Shift shortcuts
    if (e.shiftKey && key === "s") { e.preventDefault(); saveScore(); return; }
    if (e.shiftKey && key === "o") { e.preventDefault(); openScore(); return; }
    if (e.shiftKey && key === "backspace") { e.preventDefault(); setNotes([]); setRepeats({}); setSelectedIdx(null); return; }

    if (DURATION_KEYS[e.key]) {
      const newDur = DURATION_KEYS[e.key].value;
      if (selectedIdx !== null) updateSelectedNote("duration", newDur);
      setDuration(newDur);
      return;
    }
    if (key === ".") {
      if (selectedIdx !== null) {
        const note = notes[selectedIdx];
        updateSelectedNote("dotted", !note.dotted);
      }
      setDotted(d => !d);
      return;
    }
    if (key === "[") {
      if (selectedIdx !== null) {
        const note = notes[selectedIdx];
        updateSelectedNote("triplet", !note.triplet);
      }
      setTriplet(t => { if (!t) setSlur(false); return !t; });
      return;
    }
    if (key === ",") {
      if (selectedIdx !== null) {
        const note = notes[selectedIdx];
        updateSelectedNote("slur", !note.slur);
      }
      setSlur(s => { if (!s) setTriplet(false); return !s; });
      return;
    }
    if (key === "v") {
      const toggle = a => a === "sharp" ? null : "sharp";
      if (selectedIdx !== null) updateSelectedNote("accidental", toggle(notes[selectedIdx]?.accidental));
      setAccidental(toggle);
      return;
    }
    if (key === "b") {
      const toggle = a => a === "flat" ? null : "flat";
      if (selectedIdx !== null) updateSelectedNote("accidental", toggle(notes[selectedIdx]?.accidental));
      setAccidental(toggle);
      return;
    }
    if (key === "n") {
      const toggle = a => a === "natural" ? null : "natural";
      if (selectedIdx !== null) updateSelectedNote("accidental", toggle(notes[selectedIdx]?.accidental));
      setAccidental(toggle);
      return;
    }

    if (key === "0") {
      setNoteSystem(ns => ns === "solfeo" ? "letter" : "solfeo");
      return;
    }

    if (key === "/") {
      e.preventDefault();
      setTimeSignature(ts => {
        const idx = TIME_SIGNATURES.findIndex(sig => sig.label === ts.label);
        const newIdx = idx >= TIME_SIGNATURES.length - 1 ? 0 : idx + 1;
        return TIME_SIGNATURES[newIdx];
      });
      return;
    }

    if (key === "?") { setHideLabels(h => !h); return; }

    if (key === "p") {
      if (isPlaying) stopPlayback(); else startPlayback();
      return;
    }
    if (key === "m") { setIsMuted(m => !m); return; }
    if (key === "k") { setShowShortcuts(s => !s); return; }
    if (key === "l") { i18n.changeLanguage(i18n.language === "es" ? "en" : "es"); return; }

    if (key === "backspace" || key === "delete") {
      e.preventDefault();
      if (selectedIdx !== null) {
        setNotes(ns => ns.filter((_, i) => i !== selectedIdx));
        setSelectedIdx(null);
      } else {
        setNotes(ns => ns.length > 0 ? ns.slice(0, -1) : ns);
      }
      return;
    }

    if (key === "escape") { setSelectedIdx(null); setShowShortcuts(false); return; }

    if (key === " ") {
      e.preventDefault();
      addRest();
      return;
    }

    const noteData = KEY_TO_NOTE[key];
    if (noteData) addNote(noteData);
  }, [selectedIdx, notes, addNote, addRest, updateSelectedNote, isPlaying, startPlayback, stopPlayback, saveScore, openScore]);

  // ── Pointer helpers ─────────────────────────────────────────────────────────
  function getSVGCoords(e, svgEl) {
    const rect    = svgEl.getBoundingClientRect();
    const clientX = e.touches ? e.touches[0].clientX : e.clientX;
    const clientY = e.touches ? e.touches[0].clientY : e.clientY;
    const scale   = rect.width / svgEl.getAttribute("width");
    return { x: (clientX - rect.left) / scale, y: (clientY - rect.top) / scale - 18 };
  }

  // ── Derived values ─────────────────────────────────────────────────────────
  const totalBeats = getTotalBeats(notes);
  const beatsPerMeasure = timeSignature.beats;
  const beatsPerLine = MEASURES_PER_LINE * beatsPerMeasure;
  const referenceBeatsPerLine = MEASURES_PER_LINE * 4; // always use 4/4 width
  const scaledBeatWidth = BEAT_WIDTH * (referenceBeatsPerLine / beatsPerLine);
  const staffWidth = NOTE_START_X + referenceBeatsPerLine * BEAT_WIDTH + 20;
  const noteX = (beatPosition) => getNoteX(beatPosition, scaledBeatWidth);
  const nextNoteBeatValue = getDurationBeatValue(duration, dotted, triplet);

  const rawCurrentLine = Math.floor(totalBeats / beatsPerLine);
  const beatsOnRawLine = totalBeats % beatsPerLine;
  const canFitOnRawLine = beatsOnRawLine + nextNoteBeatValue <= beatsPerLine;

  const currentLine = canFitOnRawLine ? rawCurrentLine : rawCurrentLine + 1;
  const beatsOnCurrentLine = canFitOnRawLine ? beatsOnRawLine : 0;

  const totalLines = Math.max(1, currentLine + 1);

  function getNotesForLine(lineIdx) {
    const lineStartBeat = lineIdx * beatsPerLine;
    const lineEndBeat = (lineIdx + 1) * beatsPerLine;
    const lineNotes = [];
    let accumulatedBeats = 0;

    for (const note of notes) {
      const noteBeatValue = getNoteBeatValue(note);
      const noteStartBeat = note.startBeat !== undefined ? note.startBeat : accumulatedBeats;

      if (noteStartBeat >= lineStartBeat && noteStartBeat < lineEndBeat) {
        lineNotes.push({ ...note, beatPosition: noteStartBeat - lineStartBeat });
      }

      accumulatedBeats = noteStartBeat + noteBeatValue;
    }

    return lineNotes;
  }

  function handleStaffPointerMove(e, lineIdx) {
    const svgEl = svgRefs.current[lineIdx];
    if (!svgEl) return;
    const { x, y } = getSVGCoords(e, svgEl);
    if (x < STAFF_LEFT || x > staffWidth) { setGhostNote(null); return; }
    const pos = yToPos(y);
    const noteData = STAFF_NOTES[pos];
    if (!noteData || lineIdx !== currentLine) {
      setGhostNote(null);
      return;
    }
    setGhostNote({ pos, noteData, lineIdx });
  }

  function handleStaffClick(e, lineIdx) {
    const svgEl = svgRefs.current[lineIdx];
    if (!svgEl) return;
    const { x, y } = getSVGCoords(e, svgEl);
    if (x < STAFF_LEFT || x > staffWidth) return;
    const pos = yToPos(y);
    const noteData = STAFF_NOTES[pos];
    if (noteData && lineIdx === currentLine) {
      addNote(noteData);
    }
    setGhostNote(null);
  }

  const deleteSelected = useCallback(() => {
    setNotes(ns => ns.filter((_, i) => i !== selectedIdx));
    setSelectedIdx(null);
  }, [selectedIdx]);

  // ── Drag state ─────────────────────────────────────────────────────────────
  const draggingRef = useRef(null);

  function handleNoteDragStart(e, globalIdx, lineIdx) {
    e.stopPropagation();
    const note = notes[globalIdx];
    if (note.isRest) return;
    draggingRef.current = { globalIdx, lineIdx, startY: e.clientY || (e.touches && e.touches[0].clientY), moved: false };
    setSelectedIdx(globalIdx);
  }

  function handleNoteDragMove(e, lineIdx) {
    if (!draggingRef.current || draggingRef.current.lineIdx !== lineIdx) return;
    const clientY = e.clientY || (e.touches && e.touches[0].clientY);
    if (Math.abs(clientY - draggingRef.current.startY) > 4) {
      draggingRef.current.moved = true;
    }
    if (!draggingRef.current.moved) return;

    const svgEl = svgRefs.current[lineIdx];
    if (!svgEl) return;
    const { y } = getSVGCoords(e, svgEl);
    const pos = yToPos(y);
    const noteData = STAFF_NOTES[pos];
    if (noteData) {
      const idx = draggingRef.current.globalIdx;
      setNotes(ns => {
        if (ns[idx].pos === pos) return ns;
        const updated = [...ns];
        updated[idx] = { ...ns[idx], pos, note: noteData.note, octave: noteData.octave };
        return updated;
      });
    }
  }

  function handleNoteDragEnd(e) {
    if (draggingRef.current && draggingRef.current.moved) {
      const note = notes[draggingRef.current.globalIdx];
      if (note) playNote(note.note, note.octave, note.accidental);
    }
    draggingRef.current = null;
  }

  // ── Render ───────────────────────────────────────────────────────────────────
  return (
    <div
      ref={containerRef}
      tabIndex={0}
      onKeyDown={handleKeyDown}
      className="app"
    >
      {/* Menu bar */}
      <MenuBar duration={duration} setDuration={setDuration} dotted={dotted} setDotted={setDotted} triplet={triplet} setTriplet={setTriplet} slur={slur} setSlur={setSlur} addRest={addRest} accidental={accidental} setAccidental={setAccidental} isMuted={isMuted} setIsMuted={setIsMuted} isPlaying={isPlaying} startPlayback={startPlayback} stopPlayback={stopPlayback} tempo={tempo} setTempo={setTempo} hasNotes={notes.length > 0} noteCount={notes.length} notes={notes} setNotes={setNotes} selectedIdx={selectedIdx} setSelectedIdx={setSelectedIdx} updateSelectedNote={updateSelectedNote} noteSystem={noteSystem} setNoteSystem={setNoteSystem} timeSignature={timeSignature} setTimeSignature={setTimeSignature} hideLabels={hideLabels} setHideLabels={setHideLabels} showShortcuts={showShortcuts} setShowShortcuts={setShowShortcuts} saveScore={saveScore} openScore={openScore} onAfterChange={focusContainer} />

      {/* Staff */}
      <div className="staff-container-wrapper">
      <div className="staff-container" style={{ maxWidth: staffWidth + 30 }}>
        {Array.from({ length: totalLines }).map((_, lineIdx) => {
          const lineNotes = getNotesForLine(lineIdx);
          const isCurrentLine = lineIdx === currentLine;
          const showGhost = ghostNote && ghostNote.lineIdx === lineIdx && isCurrentLine;

          return (
            <svg
              key={lineIdx}
              ref={el => svgRefs.current[lineIdx] = el}
              width={staffWidth}
              height={LINE_GAP * 4 + 130}
              style={{ display:"block", cursor: isCurrentLine ? "crosshair" : "default" }}
              onMouseMove={e => { handleNoteDragMove(e, lineIdx); handleStaffPointerMove(e, lineIdx); }}
              onMouseUp={e => handleNoteDragEnd(e)}
              onMouseLeave={() => { handleNoteDragEnd(); setGhostNote(null); }}
              onClick={e => { if (!draggingRef.current?.moved) handleStaffClick(e, lineIdx); }}
              onTouchStart={e => { e.preventDefault(); handleStaffClick(e, lineIdx); }}
              onTouchMove={e => { e.preventDefault(); handleNoteDragMove(e, lineIdx); handleStaffPointerMove(e, lineIdx); }}
            >
              <g transform="translate(0,18)">
                {/* Measure number */}
                {lineIdx > 0 && (
                  <text
                    x={24}
                    y={40}
                    fontSize={12}
                    fontWeight={600}
                    fontFamily="system-ui, -apple-system, sans-serif"
                    fill="#000000"
                    textAnchor="end"
                  >
                    {lineIdx * MEASURES_PER_LINE + 1}
                  </text>
                )}

                {/* Staff lines */}
                {[0,1,2,3,4].map(i => (
                  <line key={i}
                    x1={STAFF_LEFT+2} y1={STAFF_TOP + i * LINE_GAP}
                    x2={staffWidth - 10} y2={STAFF_TOP + i * LINE_GAP}
                    stroke="#1a1a2e" strokeWidth="1.1"
                  />
                ))}

                {/* Treble clef */}
                <g transform={`translate(${STAFF_LEFT + 5}, ${STAFF_TOP - 20}) scale(0.55)`}>
                  <g transform={`translate(${G_CLEF.translateX}, ${G_CLEF.translateY})`}>
                    <path d={G_CLEF.path} fill="#1a1a2e" />
                  </g>
                </g>

                {/* Time signature (first line only) */}
                {lineIdx === 0 && (
                  <g>
                    <text x={STAFF_LEFT + 65} y={STAFF_TOP + LINE_GAP * 1}
                      fontSize={60} fontFamily="'Bravura Text', Georgia, serif" fontWeight={400} fill="#1a1a2e"
                      textAnchor="middle">
                      {String.fromCharCode(0xE080 + timeSignature.beats)}
                    </text>
                    <text x={STAFF_LEFT + 65} y={STAFF_TOP + LINE_GAP * 3}
                      fontSize={60} fontFamily="'Bravura Text', Georgia, serif" fontWeight={400} fill="#1a1a2e"
                      textAnchor="middle">
                      {String.fromCharCode(0xE080 + timeSignature.beatValue)}
                    </text>
                  </g>
                )}

                {/* Repeat start at beginning */}
                {lineIdx === 0 && repeats[0] === 'start' && (
                  <g transform={`translate(${NOTE_START_X - 5}, ${STAFF_TOP - 1}) scale(0.87)`}>
                    {REPEAT_PATHS.start.paths.map((p, i) => (
                      <path key={i} d={p} fill="#1a1a2e" />
                    ))}
                  </g>
                )}
                {lineIdx === 0 && (
                  <rect
                    x={NOTE_START_X - 10} y={STAFF_TOP - 5}
                    width={20} height={LINE_GAP * 4 + 10}
                    fill="transparent"
                    style={{ cursor: 'pointer' }}
                    onClick={(e) => {
                      e.stopPropagation();
                      setRepeats(r => {
                        const newRepeats = { ...r };
                        if (r[0] === 'start') delete newRepeats[0];
                        else newRepeats[0] = 'start';
                        return newRepeats;
                      });
                    }}
                  />
                )}

                {/* Bar lines + repeat signs */}
                {Array.from({ length: MEASURES_PER_LINE }).map((_, measureIdx) => {
                  const globalMeasure = lineIdx * MEASURES_PER_LINE + measureIdx + 1;
                  const barX = NOTE_START_X + (measureIdx + 1) * beatsPerMeasure * scaledBeatWidth;
                  const repeatType = repeats[globalMeasure];
                  const repeatScale = 0.87;
                  const repeatY = STAFF_TOP - 1;

                  return (
                    <g key={`bar-${measureIdx}`}>
                      <line
                        x1={barX} y1={STAFF_TOP}
                        x2={barX} y2={STAFF_TOP + LINE_GAP * 4}
                        stroke="#1a1a2e" strokeWidth={measureIdx === MEASURES_PER_LINE - 1 ? "2.5" : "1.5"}
                      />
                      {(repeatType === 'end' || repeatType === 'both') && (
                        <g transform={`translate(${barX - REPEAT_PATHS.end.width * repeatScale - 2 + 4}, ${repeatY}) scale(${repeatScale})`}>
                          {REPEAT_PATHS.end.paths.map((p, i) => (
                            <path key={i} d={p} fill="#1a1a2e" />
                          ))}
                        </g>
                      )}
                      {(repeatType === 'start' || repeatType === 'both') && (
                        <g transform={`translate(${barX + 3 - 4}, ${repeatY}) scale(${repeatScale})`}>
                          {REPEAT_PATHS.start.paths.map((p, i) => (
                            <path key={i} d={p} fill="#1a1a2e" />
                          ))}
                        </g>
                      )}
                      <rect
                        x={barX - 15} y={STAFF_TOP - 5}
                        width={30} height={LINE_GAP * 4 + 10}
                        fill="transparent"
                        style={{ cursor: 'pointer' }}
                        onClick={(e) => {
                          e.stopPropagation();
                          setRepeats(r => {
                            const current = r[globalMeasure];
                            let next;
                            if (!current) next = 'end';
                            else if (current === 'end') next = 'start';
                            else if (current === 'start') next = 'both';
                            else next = undefined;

                            const newRepeats = { ...r };
                            if (next) newRepeats[globalMeasure] = next;
                            else delete newRepeats[globalMeasure];
                            return newRepeats;
                          });
                        }}
                      />
                    </g>
                  );
                })}

                {/* Playhead */}
                {isPlaying && (() => {
                  const playheadLine = Math.floor(playheadBeat / beatsPerLine);
                  if (playheadLine === lineIdx) {
                    const beatOnLine = playheadBeat % beatsPerLine;
                    const playheadX = noteX(beatOnLine);
                    return (
                      <line
                        x1={playheadX} y1={STAFF_TOP - 10}
                        x2={playheadX} y2={STAFF_TOP + LINE_GAP * 4 + 10}
                        stroke="#e63946" strokeWidth="2"
                        strokeLinecap="round"
                      />
                    );
                  }
                  return null;
                })()}

                {/* Ghost note */}
                {showGhost && (
                  <NoteHead
                    x={noteX(snapToGrid(beatsOnCurrentLine, duration, triplet))}
                    y={staffY(ghostNote.pos)}
                    duration={duration} selected={false}
                    dotted={dotted} accidental={accidental}
                    pos={ghostNote.pos} ghost={true}
                    noteLabel={noteName(ghostNote.noteData.note, noteSystem, accidental)}
                    hideLabel={hideLabels}
                  />
                )}

                {/* Notes + beams */}
                {(() => {
                  const beamGroups = calculateBeamGroups(lineNotes, beatsPerMeasure);

                  // Build per-note x adjustments for beamed sixteenth groups
                  const sixteenthXAdjust = new Map();
                  beamGroups.forEach(group => {
                    if (group[0].duration === "sixteenth") {
                      group.forEach((note, i) => {
                        sixteenthXAdjust.set(note.id, i * SIXTEENTH_GAP_ADJUST);
                      });
                    }
                  });

                  const getNoteRenderInfo = (note) => ({
                    x: noteX(note.beatPosition) + (sixteenthXAdjust.get(note.id) || 0),
                    y: staffY(note.pos),
                    pos: note.pos
                  });

                  const noteBeamDirection = new Map();
                  beamGroups.forEach(group => {
                    const isUp = getBeamDirection(group, getNoteRenderInfo);
                    group.forEach(note => {
                      noteBeamDirection.set(note.id, isUp);
                    });
                  });

                  return (
                    <>
                      <Beams beamGroups={beamGroups} getNoteRenderInfo={getNoteRenderInfo} />

                      {lineNotes.map((note) => {
                        const x = noteX(note.beatPosition) + (sixteenthXAdjust.get(note.id) || 0);
                        const globalIdx = notes.findIndex(n => n.id === note.id);

                        if (note.isRest) {
                          return (
                            <g key={note.id}
                              onClick={ev => { ev.stopPropagation(); setSelectedIdx(globalIdx === selectedIdx ? null : globalIdx); }}
                              onTouchEnd={ev => { ev.preventDefault(); ev.stopPropagation(); setSelectedIdx(globalIdx === selectedIdx ? null : globalIdx); }}
                              style={{ cursor:"pointer" }}>
                              <rect x={x-16} y={STAFF_TOP} width={32} height={LINE_GAP*4} fill="transparent"/>
                              <RestHead x={x} duration={note.duration}
                                selected={selectedIdx === globalIdx}
                                dotted={note.dotted}
                                hideLabel={hideLabels}
                                restLabel={t("controls.restLabel")}
                              />
                            </g>
                          );
                        }

                        const y = staffY(note.pos);
                        const label = noteName(note.note, noteSystem, note.accidental);
                        const isBeamed = noteBeamDirection.has(note.id);
                        const forceDirection = isBeamed ? noteBeamDirection.get(note.id) : undefined;

                        return (
                          <g key={note.id}
                            onMouseDown={ev => { handleNoteDragStart(ev, globalIdx, lineIdx); }}
                            onMouseMove={ev => { handleNoteDragMove(ev, lineIdx); }}
                            onMouseUp={ev => { if (!draggingRef.current?.moved) { ev.stopPropagation(); setSelectedIdx(globalIdx === selectedIdx ? null : globalIdx); } handleNoteDragEnd(ev); }}
                            onMouseLeave={ev => { handleNoteDragEnd(ev); }}
                            onTouchStart={ev => { ev.preventDefault(); handleNoteDragStart(ev, globalIdx, lineIdx); }}
                            onTouchMove={ev => { ev.preventDefault(); handleNoteDragMove(ev, lineIdx); }}
                            onTouchEnd={ev => { ev.preventDefault(); ev.stopPropagation(); if (!draggingRef.current?.moved) { setSelectedIdx(globalIdx === selectedIdx ? null : globalIdx); } handleNoteDragEnd(ev); }}
                            style={{ cursor:"pointer" }}>
                            <rect x={x-16} y={y-26} width={32} height={52} fill="transparent"/>
                            <NoteHead x={x} y={y} duration={note.duration}
                              selected={selectedIdx === globalIdx}
                              dotted={note.dotted} accidental={note.accidental}
                              pos={note.pos} noteLabel={label}
                              beamed={isBeamed}
                              forceDirection={forceDirection}
                              hideLabel={hideLabels}
                            />
                          </g>
                        );
                      })}

                      {/* Slur/tie curves */}
                      {(() => {
                        const curves = [];
                        for (let i = 0; i < lineNotes.length; i++) {
                          const note = lineNotes[i];
                          if (!note.slur || note.isRest) continue;
                          // Find the next note in lineNotes
                          const nextNote = lineNotes[i + 1];
                          if (!nextNote || nextNote.isRest) continue;

                          const x1 = noteX(note.beatPosition) + (sixteenthXAdjust.get(note.id) || 0);
                          const x2 = noteX(nextNote.beatPosition) + (sixteenthXAdjust.get(nextNote.id) || 0);
                          const y1 = staffY(note.pos);
                          const y2 = staffY(nextNote.pos);

                          // Determine curve direction based on stem directions
                          const stemUp1 = noteBeamDirection.has(note.id) ? noteBeamDirection.get(note.id) : note.pos < 9;
                          const stemUp2 = noteBeamDirection.has(nextNote.id) ? noteBeamDirection.get(nextNote.id) : nextNote.pos < 9;

                          // If both stems up, curve below; if both down, curve above; if mixed, curve above
                          const curveBelow = stemUp1 && stemUp2;
                          const offset = curveBelow ? 24 : -24;
                          const startY = y1 + (curveBelow ? 6 : -6);
                          const endY = y2 + (curveBelow ? 6 : -6);
                          const midX = (x1 + x2) / 2;
                          const outerCpY = (startY + endY) / 2 + offset;
                          const innerCpY = (startY + endY) / 2 + offset * 0.85;

                          curves.push(
                            <path
                              key={`slur-${note.id}`}
                              d={`M${x1 - 2},${startY} Q${midX},${outerCpY} ${x2 + 2},${endY} Q${midX},${innerCpY} ${x1 - 2},${startY} Z`}
                              fill="#1a1a2e"
                            />
                          );
                        }
                        return curves;
                      })()}

                      {/* Triplet brackets */}
                      {(() => {
                        const brackets = [];
                        let i = 0;
                        while (i < lineNotes.length) {
                          const note = lineNotes[i];
                          if (note.triplet) {
                            let groupEnd = i;
                            while (
                              groupEnd < lineNotes.length &&
                              lineNotes[groupEnd].triplet &&
                              lineNotes[groupEnd].duration === note.duration
                            ) {
                              groupEnd++;
                            }
                            const groupSize = groupEnd - i;
                            if (groupSize >= 1) {
                              const firstNote = lineNotes[i];
                              const lastNote = lineNotes[groupEnd - 1];
                              const x1 = noteX(firstNote.beatPosition) - 8;
                              const x2 = noteX(lastNote.beatPosition) + 8;
                              const bracketY = STAFF_TOP - 18;
                              brackets.push(
                                <g key={`triplet-${firstNote.id}`}>
                                  <line x1={x1} y1={bracketY} x2={x1} y2={bracketY + 5} stroke="#1a1a2e" strokeWidth="1.5"/>
                                  <line x1={x1} y1={bracketY} x2={(x1 + x2) / 2 - 8} y2={bracketY} stroke="#1a1a2e" strokeWidth="1.5"/>
                                  <text x={(x1 + x2) / 2} y={bracketY + 4} textAnchor="middle" fontSize="11" fontWeight="bold" fill="#1a1a2e" fontFamily="Georgia, serif">3</text>
                                  <line x1={(x1 + x2) / 2 + 8} y1={bracketY} x2={x2} y2={bracketY} stroke="#1a1a2e" strokeWidth="1.5"/>
                                  <line x1={x2} y1={bracketY} x2={x2} y2={bracketY + 5} stroke="#1a1a2e" strokeWidth="1.5"/>
                                </g>
                              );
                            }
                            i = groupEnd;
                          } else {
                            i++;
                          }
                        }
                        return brackets;
                      })()}
                    </>
                  );
                })()}
              </g>
            </svg>
          );
        })}
      </div>
      </div>

    </div>
  );
}
